const repo = $input.first().json.gh_repo;
const keywords = $input.first().json.keywords;
const date = new Date();
date.setDate(date.getDate() - 180);
const dateString = date.toISOString().split('T')[0];
const chunks = [];
for (let i = 0; i < keywords.length; i += 5) {
  chunks.push(keywords.slice(i, i + 5));
}
return chunks.map(chunk => ({
  query: `repo:${repo} type:pr created:>${dateString} in:title (${chunk.join(' OR ')})`,
  repo_owner: repo.split('/')[0],
  repo_name: repo.split('/')[1]
}));

const all_responses = $input.all();
const pr_numbers = new Set();
const prs = [];
for (const response of all_responses) {
  const items = response.json.items || [];
  for (const item of items) {
    const title = item.title || "";
    if (title.toLowerCase().includes("[backport")) continue;
    if (item.state === 'open' || (item.pull_request && item.pull_request.merged_at)) {
      if (!pr_numbers.has(item.number)) {
        pr_numbers.add(item.number);
        prs.push(item);
      }
    }
  }
}
return {
  pr_numbers: Array.from(pr_numbers),
  prs: prs
};

const all_items = $input.all();
const cached_item = all_items[0]?.json?.data?.[0] || {};
const cur = all_items[1]?.json || {};
const pr_numbers_prev = cached_item.pr_numbers || [];
const pr_numbers_cur = cur.pr_numbers || [];
const pr_numbers_diff = pr_numbers_cur.filter(x => !pr_numbers_prev.includes(x));
const new_prs_data = (cur.prs || []).filter(x => pr_numbers_diff.includes(x.number));
return {
  pr_numbers: { prev: pr_numbers_prev, cur: pr_numbers_cur, diff: pr_numbers_diff },
  prs: new_prs_data
};

const item = $input.first().json;
const new_prs = item.prs || [];
if (new_prs.length === 0) return [];
const keywords = $node["Config"].json.keywords || [];
const workflowId = $workflow.id;
const workflowName = $workflow.name;
const executionId = $execution.id;
const escapeHtml = (unsafe) => (unsafe || "").toString().replace(/&/g, "&amp;").replace(/</g, "&lt;").replace(/>/g, "&gt;").replace(/"/g, "&quot;").replace(/'/g, "&#039;");
const formatDate = (isoString) => {
  if (!isoString) return "N/A";
  const d = new Date(isoString);
  const months = ["Jan", "Feb", "Mar", "Apr", "May", "Jun", "Jul", "Aug", "Sep", "Oct", "Nov", "Dec"];
  return `${months[d.getMonth()]} ${d.getDate()}`;
};

// Verified GitHub notification email assets (PNG via Shields.io)
// These load reliably in Gmail unlike SVGs or dead GitHub asset URLs
const IMG_PR_OPEN = 'https://img.shields.io/badge/-%20-238636.png?logo=git-pull-request&logoColor=white';
const IMG_PR_MERGED = 'https://img.shields.io/badge/-%20-8957e5.png?logo=git-merge&logoColor=white';

const groupedPrs = {};
for (const kw of keywords) groupedPrs[kw] = [];
for (const pr of new_prs) {
  const titleLower = pr.title.toLowerCase();
  for (const kw of keywords) if (titleLower.includes(kw.toLowerCase())) groupedPrs[kw].push(pr);
}

// Complex Sort: 1. Merged first, 2. Open next. Within each group, sort by relevant date (newest first).
for (const kw of keywords) {
  groupedPrs[kw].sort((a, b) => {
    const aMerged = !!(a.pull_request && a.pull_request.merged_at);
    const bMerged = !!(b.pull_request && b.pull_request.merged_at);

    // 1. Prioritize Merged over Open
    if (aMerged && !bMerged) return -1;
    if (!aMerged && bMerged) return 1;

    // 2. Within the same state, sort by date (newest first)
    const aDate = new Date(aMerged ? a.pull_request.merged_at : a.created_at);
    const bDate = new Date(bMerged ? b.pull_request.merged_at : b.created_at);
    return bDate - aDate;
  });
}

